/**
 * Connect-Protocol-Version
 *
 * Define the version of the Connect protocol
 */
export type ConnectProtocolVersion = 1;

/**
 * Connect-Timeout-Ms
 *
 * Define the timeout, in ms
 */
export type ConnectTimeoutHeader = number;

/**
 * Connect Error
 *
 * Error type returned by Connect: https://connectrpc.com/docs/go/errors/#http-representation
 */
export type ConnectError = {
    /**
     * The status code, which should be an enum value of [google.rpc.Code][google.rpc.Code].
     */
    code?: 'canceled' | 'unknown' | 'invalid_argument' | 'deadline_exceeded' | 'not_found' | 'already_exists' | 'permission_denied' | 'resource_exhausted' | 'failed_precondition' | 'aborted' | 'out_of_range' | 'unimplemented' | 'internal' | 'unavailable' | 'data_loss' | 'unauthenticated';
    /**
     * A developer-facing error message, which should be in English. Any user-facing error message should be localized and sent in the [google.rpc.Status.details][google.rpc.Status.details] field, or localized by the client.
     */
    message?: string;
    /**
     * A list of messages that carry the error details. There is no limit on the number of messages.
     */
    details?: Array<ConnectErrorDetailsAny>;
    [key: string]: unknown;
};

/**
 * Contains an arbitrary serialized message along with a @type that describes the type of the serialized message, with an additional debug field for ConnectRPC error details.
 */
export type ConnectErrorDetailsAny = {
    /**
     * A URL that acts as a globally unique identifier for the type of the serialized message. For example: `type.googleapis.com/google.rpc.ErrorInfo`. This is used to determine the schema of the data in the `value` field and is the discriminator for the `debug` field.
     */
    type?: string;
    /**
     * The Protobuf message, serialized as bytes and base64-encoded. The specific message type is identified by the `type` field.
     */
    value?: Blob | File;
    /**
     * Any
     *
     * Detailed error information.
     */
    debug?: {
        [key: string]: unknown;
    };
    [key: string]: unknown;
};

